import useData, { getTotalAmount } from "../useData"
import useSplitStore from "../useSplitStore"

function Title() {
    const { data, loading, error } = useData(getTotalAmount)
    const { totalAmount } = useSplitStore((s) => s)

    return (
        <>
            <div className='text-blue-500'>Split Payments</div>
            <div className='text-blue-500'>{totalAmount}</div>
        </>
    )
}

export default Title
